  1	import * as React from 'react';
  2	import {
  3	  DO_NOT_DELETE_PVC_ANNOTATION_WO_SLASH,
  4	  PROTECTED_APP_ANNOTATION,
  5	  PROTECTED_APP_ANNOTATION_WO_SLASH,
  6	} from '@odf/mco/constants';
  7	import { DRPlacementControlKind } from '@odf/mco/types';
  8	import { ACMPlacementModel, DRPlacementControlModel } from '@odf/shared';
  9	import {
 10	  ModalBody,
 11	  ModalFooter,
 12	  ModalHeader,
 13	  CommonModalProps,
 14	} from '@odf/shared/modals';
 15	import { getAnnotations, getName, getNamespace } from '@odf/shared/selectors';
 16	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 17	import { getErrorMessage } from '@odf/shared/utils';
 18	import {
 19	  K8sResourceKind,
 20	  k8sDelete,
 21	  k8sGet,
 22	  k8sPatch,
 23	} from '@openshift-console/dynamic-plugin-sdk';
 24	import { Trans } from 'react-i18next';
 25	import {
 26	  Alert,
 27	  AlertVariant,
 28	  Button,
 29	  ButtonVariant,
 30	  Modal,
 31	  ModalVariant,
 32	} from '@patternfly/react-core';
 33	import { ExclamationTriangleIcon } from '@patternfly/react-icons';
 34	
 35	// ToDo(Gowtham): https://github.com/red-hat-storage/odf-console/issues/1449
 36	const pvcAnnotationPatchPromise = async (
 37	  application: DRPlacementControlKind
 38	) => {
 39	  const patch = [
 40	    {
 41	      op: 'add',
 42	      path: `/metadata/annotations/${DO_NOT_DELETE_PVC_ANNOTATION_WO_SLASH}`,
 43	      value: 'true',
 44	    },
 45	  ];
 46	
 47	  return k8sPatch({
 48	    model: DRPlacementControlModel,
 49	    resource: {
 50	      metadata: {
 51	        name: getName(application),
 52	        namespace: getNamespace(application),
 53	      },
 54	    },
 55	    data: patch,
 56	  });
 57	};
 58	
 59	const experimentalAnnotationRemovalPatchPromise = async (
 60	  application: DRPlacementControlKind
 61	) => {
 62	  try {
 63	    const name = application.spec.placementRef.name;
 64	    const namespace = getNamespace(application);
 65	
 66	    const placement = await k8sGet({
 67	      model: ACMPlacementModel,
 68	      name,
 69	      ns: namespace,
 70	    });
 71	
 72	    const annotations = getAnnotations(placement, {});
 73	
 74	    if (!annotations || !annotations[PROTECTED_APP_ANNOTATION]) {
 75	      return Promise.resolve();
 76	    }
 77	
 78	    const patch = [
 79	      {
 80	        op: 'remove',
 81	        path: `/metadata/annotations/${PROTECTED_APP_ANNOTATION_WO_SLASH}`,
 82	      },
 83	    ];
 84	
 85	    return k8sPatch({
 86	      model: ACMPlacementModel,
 87	      resource: placement,
 88	      data: patch,
 89	    });
 90	  } catch (err) {
 91	    return Promise.reject(err);
 92	  }
 93	};
 94	
 95	// ToDo(Gowtham): https://github.com/red-hat-storage/odf-console/issues/1449
 96	const deleteApplicationResourcePromise = (
 97	  application: DRPlacementControlKind
 98	) => {
 99	  // Delete DRPC and dummy placement after updating the annotation
100	  const promises: Promise<K8sResourceKind>[] = [];
101	  const { name, namespace } = application?.spec?.placementRef;
102	
103	  promises.push(
104	    k8sDelete({
105	      resource: application,
106	      model: DRPlacementControlModel,
107	      json: null,
108	      requestInit: null,
109	    })
110	  );
111	
112	  promises.push(
113	    k8sDelete({
114	      resource: {
115	        metadata: {
116	          name: name,
117	          namespace: namespace,
118	        },
119	      },
120	      model: ACMPlacementModel,
121	      json: null,
122	      requestInit: null,
123	    })
124	  );
125	
126	  return promises;
127	};
128	
129	const RemoveDisasterRecoveryModal: React.FC<
130	  CommonModalProps<RemoveDisasterRecoveryProps>
131	> = ({ closeModal, isOpen, extraProps: { application } }) => {
132	  const { t } = useCustomTranslation();
133	
134	  const [isInprogress, setInProgress] = React.useState(false);
135	  const [error, setError] = React.useState();
136	
137	  const onRemove = async (event) => {
138	    event.preventDefault();
139	    setInProgress(true);
140	
141	    try {
142	      await experimentalAnnotationRemovalPatchPromise(application);
143	      await pvcAnnotationPatchPromise(application);
144	      await Promise.all(deleteApplicationResourcePromise(application));
145	      closeModal();
146	    } catch (err) {
147	      setError(err);
148	      setInProgress(false);
149	    }
150	  };
151	
152	  return (
153	    <Modal
154	      variant={ModalVariant.small}
155	      header={
156	        <ModalHeader>
157	          <ExclamationTriangleIcon
158	            color="var(--pf-t--global--color--status--warning--default)"
159	            className="icon--spacer"
160	          />
161	          {t('Remove disaster recovery?')}
162	        </ModalHeader>
163	      }
164	      isOpen={isOpen}
165	      onClose={closeModal}
166	      showClose={false}
167	      hasNoBodyWrapper={true}
168	    >
169	      <ModalBody>
170	        <Trans t={t}>
171	          Your application{' '}
172	          <strong>{{ resourceName: getName(application) }}</strong> will lose
173	          disaster recovery protection, preventing volume synchronization
174	          (replication) between clusters.
175	        </Trans>
176	        {!!error && (
177	          <Alert
178	            isInline
179	            variant={AlertVariant.danger}
180	            title={t('An error occurred')}
181	          >
182	            {getErrorMessage(error) || error}
183	          </Alert>
184	        )}
185	      </ModalBody>
186	      <ModalFooter>
187	        <Button
188	          key="cancel"
189	          variant={ButtonVariant.secondary}
190	          onClick={closeModal}
191	          data-test="cancel-action"
192	        >
193	          {t('Cancel')}
194	        </Button>
195	        <Button
196	          key="remove"
197	          variant={ButtonVariant.danger}
198	          onClick={onRemove}
199	          data-test="remove-action"
200	          isLoading={isInprogress}
201	        >
202	          {t('Remove')}
203	        </Button>
204	      </ModalFooter>
205	    </Modal>
206	  );
207	};
208	
209	type RemoveDisasterRecoveryProps = {
210	  application: DRPlacementControlKind;
211	};
212	
213	export default RemoveDisasterRecoveryModal;

